Help me develop this:

 System Description: "You are asked to implement a Python function that determines whether a set of resource requests can be satisfied given limited capacity. The function takes as input a list of requests and available resources and returns whether a valid allocation exists. The goal is to determine feasibility of allocation based on the provided information. You may assume inputs are provided in a reasonable and consistent format. You may use ChatGPT to assist with reasoning about the problem, generating code, or writing tests."

 Function signature: "def is_allocation_feasible(
 resources: Dict[str, Number],
 requests: List[Dict[str, Number]]
 ) -> bool" 

 For the development, consider the following information:

 System Goal: To determine, based on information given, whether allocation of a resource is feasible

 Inputs: Shared inputs as next lab elec

 Outputs: Whether allocation is feasible or not (True or False)

 Functional requirements: [{'fr_1': '', 'fr_10': '', 'fr_2': 'The system shall determine if an allocation is feasible iff the requested quantity is less than or equal to the available amount', 'fr_3': '', 'fr_4': '', 'fr_5': '', 'fr_6': '', 'fr_7': '', 'fr_8': '', 'fr_9': ''}]

 Constraints: [{'c_1': 'Same constraints as next lab dec upper constraint 5', 'c_2': '', 'c_3': '', 'c_4': '', 'c_5': '', 'c_6': ''}]

 Invariants: [{'inv_1': '', 'inv_2': '', 'inv_3': ''}]

 Negative requirements: [{'neg_req_1': '', 'neg_req_2': ''}]

 Tie breaking rule: nan

 Exception: nan
LLM Response 1: from typing import Dict, List, Union
import math

Number = Union[int, float]

def is_allocation_feasible(
 resources: Dict[str, Number],
 requests: List[Dict[str, Number]]
) -> bool:
 # Validate resources
 if not resources:
 raise ValueError("Resource dictionary cannot be empty")

 for res, qty in resources.items():
 if isinstance(qty, bool) or not isinstance(qty, (int, float)):
 raise TypeError(f"Resource '{res}' must be a numeric value, not {type(qty).__name__}")
 if qty < 0 or math.isnan(qty):
 raise ValueError(f"Resource '{res}' must be non-negative and not NaN")

 # Empty requests are trivially feasible
 if not requests:
 return True

 # Initialize total demand dictionary
 total_demand: Dict[str, Number] = {res: 0 for res in resources}

 # Sum up all requests
 for i, request in enumerate(requests):
 if not isinstance(request, dict):
 raise TypeError(f"Request at index {i} must be a dictionary")
 for res, qty in request.items():
 if res not in resources:
 raise ValueError(f"Request asks for unknown resource '{res}'")
 if isinstance(qty, bool) or not isinstance(qty, (int, float)):
 raise TypeError(f"Request quantity for '{res}' must be numeric, not {type(qty).__name__}")
 if qty < 0 or math.isnan(qty):
 raise ValueError(f"Request quantity for '{res}' must be non-negative and not NaN")
 total_demand[res] += qty

 # Check if total demand exceeds available resources
 for res, demand in total_demand.items():
 if demand > resources[res]:
 return False

 return True

